const resp = $.steps.searchContext.response || {};
const data = resp.data || resp;
const results = data.results || [];

let context = '';
const sources = [];

results.slice(0, 5).forEach((r, i) => {
  const title = r.title || 'Untitled';
  const url = r.url || '';
  const text = (r.text || '').slice(0, 1500);
  context += 'Source ' + (i + 1) + ': ' + title + '\n' + text + '\n\n';
  sources.push({ title, url });
});

return { context, sources, sourceCount: results.length };

const question = $.input.question;
const style = $.input.conversationStyle || 'friendly and informative';
const searchData = $.steps.parseSearchResults.output;

let prompt = 'You are an engaging conversational AI with a ' + style + ' personality. Answer the question using the research context provided.\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'RESEARCH CONTEXT:\n' + searchData.context + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Respond in a natural, conversational tone\n';
prompt += '- Include interesting facts and insights from the research\n';
prompt += '- Ask a follow-up question to keep the conversation going\n';
prompt += '- Keep the response engaging and easy to understand\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "response": "Your conversational response",\n';
prompt += '  "keyInsights": ["interesting fact 1", "interesting fact 2"],\n';
prompt += '  "followUpQuestion": "An engaging follow-up question",\n';
prompt += '  "topic": "Main topic category",\n';
prompt += '  "mood": "informative/playful/thoughtful/exciting"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiResponse.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { response: raw, keyInsights: [], followUpQuestion: '', topic: 'General', mood: 'informative' }; }

const ai = $.steps.parseAI.output;
const sources = $.steps.parseSearchResults.output.sources;
const question = $.input.question;

const moodEmoji = { informative: ':brain:', playful: ':tada:', thoughtful: ':thought_balloon:', exciting: ':zap:' };
const emoji = moodEmoji[ai.mood] || ':speech_balloon:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: emoji + ' Conversational AI', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*You asked:* ' + question } });
blocks.push({ type: 'divider' });

const responseText = (ai.response || 'No response generated.').slice(0, 2500);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: responseText } });

if (ai.keyInsights && ai.keyInsights.length > 0) {
  blocks.push({ type: 'divider' });
  let insightsText = '*:bulb: Key Insights:*\n';
  ai.keyInsights.slice(0, 4).forEach((ins, i) => { insightsText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insightsText.slice(0, 1500) } });
}

if (ai.followUpQuestion) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:thinking_face: Want to go deeper?*\n' + ai.followUpQuestion } });
}

if (sources && sources.length > 0) {
  let srcText = '';
  sources.slice(0, 3).forEach(s => { srcText += '<' + s.url + '|' + s.title + '> '; });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':link: ' + srcText.trim() }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Search + Claude AI + One CLI' }] });

const fallback = (ai.response || '').slice(0, 150);
return { blocks, fallback };
